+#[inline]
+fn update_utf8_pending(pending: &mut u8, byte: u8) {
+    if *pending == 0 {
+        if byte < 0x80 {
+            return;
+        }
+
+        *pending = match byte {
+            0xC2..=0xDF => 1,
+            0xE0..=0xEF => 2,
+            0xF0..=0xF4 => 3,
+            _ => 0,
+        };
+        return;
+    }
+
+    if *pending > 0 {
+        if (byte & 0b1100_0000) == 0b1000_0000 {
+            *pending -= 1;
+            return;
+        }
+        // Invalid continuation - reset and treat this byte as a fresh lead byte.
+        *pending = 0;
+    }
+
+    *pending = match byte {
+        0xC2..=0xDF => 1,
+        0xE0..=0xEF => 2,
+        0xF0..=0xF4 => 3,
+        _ => 0,
+    };
+}
